import { Intent, MethodIntent, z } from 'mpay'

const stream = Intent.from({
  name: 'stream',
  schema: {
    request: z.object({
      amountPerSecond: z.string(),
      currency: z.string(),
      recipient: z.string(),
    }),
  },
})

const customStream = MethodIntent.fromIntent(stream, {
  method: 'custom',
  schema: {
    request: {
      methodDetails: z.object({
        network: z.string(),
      }),
      requires: ['recipient'],
    },
    credential: {
      payload: z.object({
        sessionId: z.string(),
        signature: z.string(),
      }),
    },
  },
})

